mapper.select:
SELECT M.MEMBER_SEQ , M.MEMBER_ID , M.MEMBER_NAME , M.BIRTH_YMD , M.EMAIL , M.GENDER , M.PHONE , M.ROLE_CODE , R.ROLE_NAME , M.STATUS , M.CREATE_DT , M.MODIFY_DT FROM MEMBER M LEFT JOIN ROLE R ON M.ROLE_CODE = R.ROLE_CODE WHERE 1 = 1
AND M.MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND M.MEMBER_NAME LIKE CONCAT('%', #{memberName}, '%')
AND M.ROLE_CODE = #{roleCode}
AND M.STATUS = #{status}
ORDER BY
M.MEMBER_ID M.MEMBER_NAME M.CREATE_DT M.MODIFY_DT M.MEMBER_SEQ
ASC DESC
LIMIT #{safeSize} OFFSET #{offset}

SELECT COUNT(*) FROM MEMBER M WHERE 1 = 1
AND M.MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND M.MEMBER_NAME LIKE CONCAT('%', #{memberName}, '%')
AND M.ROLE_CODE = #{roleCode}
AND M.STATUS = #{status}

SELECT COUNT(1)
FROM MEMBER
WHERE MEMBER_ID = #{memberId}

mapper.insert:
INSERT INTO MEMBER (
                     BIRTH_YMD
                   , CREATE_DT
                   , CREATE_ID
                   , CREATE_IP
                   , EMAIL
                   , GENDER
                   , MEMBER_ID
                   , MEMBER_NAME
                   , MODIFY_DT
                   , MODIFY_ID
                   , MODIFY_IP
                   , PHONE
                   , MEMBER_PWD
                   , ROLE_CODE
                   , STATUS
)
VALUES (
         #{birthYmd}
       , NOW()
       , #{createId}
       , #{createIp}
       , #{email}
       , #{gender}
       , #{memberId}
       , #{memberName}
       , NOW()
       , #{modifyId}
       , #{modifyIp}
       , #{phone}
       , #{memberPwd}
       , #{roleCode}
       , #{status}
       )

mapper.update:
UPDATE MEMBER
SET
    BIRTH_YMD   = #{birthYmd}
  , EMAIL       = #{email}
  , GENDER      = #{gender}
  , MEMBER_NAME = #{memberName}
  , MODIFY_DT   = NOW()
  , MODIFY_ID   = #{modifyId}
  , MODIFY_IP   = #{modifyIp}
  , PHONE       = #{phone}
  , MEMBER_PWD   = #{memberPwd}
  , ROLE_CODE   = #{roleCode}
  , STATUS      = #{status}
WHERE MEMBER_SEQ = #{memberSeq}
